package com.example.documentviewer;

import android.content.ContentResolver;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.io.IOException;
import java.io.InputStream;

public class DocumentViewerActivity extends AppCompatActivity {

    private ImageView imageView;
    private ParcelFileDescriptor pdfFileDescriptor;
    private PdfRenderer pdfRenderer;
    private PdfRenderer.Page currentPage;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        imageView = new ImageView(this);
        imageView.setLayoutParams(new ViewGroup.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        setContentView(imageView);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent == null || !Intent.ACTION_VIEW.equals(intent.getAction())) {
            showError("Unsupported intent");
            return;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            showError("No document URI provided");
            return;
        }

        String type = intent.getType();
        if (type == null) {
            type = getContentResolver().getType(uri);
        }

        closePdf();

        if (type != null && type.equals("application/pdf")) {
            displayPdf(uri);
        } else if (type != null && type.startsWith("image/")) {
            displayImage(uri);
        } else {
            String path = uri.toString().toLowerCase();
            if (path.endsWith(".pdf")) {
                displayPdf(uri);
            } else if (path.endsWith(".png") || path.endsWith(".jpg") || path.endsWith(".jpeg")
                    || path.endsWith(".gif") || path.endsWith(".webp") || path.endsWith(".bmp")) {
                displayImage(uri);
            } else {
                showError("Unsupported document type");
            }
        }
    }

    private void displayImage(Uri uri) {
        try {
            ContentResolver resolver = getContentResolver();
            InputStream inputStream = resolver.openInputStream(uri);
            if (inputStream == null) {
                showError("Unable to open image");
                return;
            }
            Bitmap bitmap;
            try {
                bitmap = BitmapFactory.decodeStream(inputStream);
            } finally {
                inputStream.close();
            }

            if (bitmap == null) {
                showError("Unable to decode image");
                return;
            }

            imageView.setImageBitmap(bitmap);
        } catch (IOException e) {
            showError("Failed to open image");
        }
    }

    private void displayPdf(Uri uri) {
        try {
            pdfFileDescriptor = getContentResolver().openFileDescriptor(uri, "r");
            if (pdfFileDescriptor == null) {
                showError("Unable to open PDF");
                return;
            }

            pdfRenderer = new PdfRenderer(pdfFileDescriptor);
            if (pdfRenderer.getPageCount() <= 0) {
                showError("PDF has no pages");
                return;
            }

            currentPage = pdfRenderer.openPage(0);
            Bitmap bitmap = Bitmap.createBitmap(
                    currentPage.getWidth(),
                    currentPage.getHeight(),
                    Bitmap.Config.ARGB_8888
            );
            currentPage.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY);
            imageView.setImageBitmap(bitmap);
        } catch (IOException e) {
            showError("Failed to open PDF");
        }
    }

    private void showError(String message) {
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
    }

    private void closePdf() {
        if (currentPage != null) {
            currentPage.close();
            currentPage = null;
        }
        if (pdfRenderer != null) {
            pdfRenderer.close();
            pdfRenderer = null;
        }
        if (pdfFileDescriptor != null) {
            try {
                pdfFileDescriptor.close();
            } catch (IOException ignored) {
            }
            pdfFileDescriptor = null;
        }
    }

    @Override
    protected void onDestroy() {
        closePdf();
        super.onDestroy();
    }
}

